<style>.toolbar{background:#fff;border-radius:10px;padding:16px;box-shadow:0 2px 10px rgba(0,0,0,.08);margin-bottom:18px}.toolbar h2{margin-bottom:8px}.search-form{display:flex;gap:10px;flex-wrap:wrap;margin-top:10px}.search-form input{flex:1 1 280px;padding:10px 12px;border:1px solid #d1d5db;border-radius:8px}.search-form a,.search-form button{padding:10px 14px;border:0;border-radius:8px;background:#2563eb;color:#fff;text-decoration:none;cursor:pointer}.search-form a{background:#6b7280}.result-meta{color:#6b7280;margin-bottom:12px}.post-item{background:#fff;border-radius:10px;padding:18px;box-shadow:0 2px 10px rgba(0,0,0,.08);margin-bottom:14px}.post-item h3{margin-bottom:8px}.post-item p{color:#374151;margin-bottom:10px}.post-meta{color:#6b7280;font-size:.9rem;margin-bottom:10px}.btn-link{display:inline-block;padding:8px 12px;border-radius:8px;background:#2563eb;color:#fff;text-decoration:none}.pagination{margin-top:16px;display:flex;gap:8px;flex-wrap:wrap}.pagination a,.pagination span{padding:8px 11px;border-radius:6px;border:1px solid #d1d5db;text-decoration:none;color:#111827;background:#fff}.pagination .current{background:#2563eb;color:#fff;border-color:#2563eb}</style><section class="toolbar"><h2>Articles sur la guerre en Iran</h2><p class="result-meta">Recherchez par mot-clé (titre ou contenu) pour filtrer les articles.</p><form action="/articles"class="search-form"><input name="q"placeholder="Ex: sanctions, diplomatie, Téhéran..."value="<?=htmlspecialchars($query ?? '')?>"> <button type="submit">Rechercher</button><?php if(!empty($query)): ?><a href="/articles">Réinitialiser</a><?php endif; ?></form></section><p class="result-meta"><?=(int)($totalPosts ?? 0)?>résultat(s)<?php if(!empty($query)): ?>pour “<?=htmlspecialchars($query)?>”<?php endif; ?></p><?php if(!empty($posts)): ?><?php foreach($posts as $post): ?><article class="post-item"><h3><?=htmlspecialchars($post['title'])?></h3><div class="post-meta">Par<?=htmlspecialchars($post['author_name']?? 'Rédaction')?>•<?=date('d/m/Y',strtotime($post['created_at']))?></div><p><?=htmlspecialchars(substr($post['content'],0,220))?>...</p><a href="/article/<?=urlencode($post['slug'])?>"class="btn-link">Lire l’article</a></article><?php endforeach; ?><?php if(($totalPages ?? 1)>1): ?><div class="pagination"><?php for($currentPage=1;$currentPage<=$totalPages;$currentPage++): ?><?php $queryString='?page='.$currentPage;if(!empty($query)){$queryString.='&q='.urlencode($query);} ?><?php if($currentPage===(int)$page): ?><span class="current"><?=$currentPage?></span><?php else: ?><a href="/articles<?=$queryString?>"><?=$currentPage?></a><?php endif; ?><?php endfor; ?></div><?php endif; ?><?php else: ?><article class="post-item"><h3>Aucun article trouvé</h3><p>Essayez un autre mot-clé ou revenez à la liste complète.</p></article><?php endif; ?>